// Build rolling 2-day filed-date window (yesterday 00:00 -> today 23:59 UTC).
// FERC posts on a ~1 business day lag; 2-day window absorbs weekend/holiday catch-up.
const now = new Date();
const end = new Date(now);
end.setUTCHours(23, 59, 59, 0);
const start = new Date(now);
start.setUTCDate(start.getUTCDate() - 1);
start.setUTCHours(0, 0, 0, 0);

const body = {
  docketSearches: [{ docketNumber: null, subDocketNumbers: [] }],
  searchText: 'interconnection OR "large load" OR co-location OR colocation OR "data center" OR "queue reform" OR "cost allocation" OR "generator interconnection" OR "surplus interconnection service" OR "network upgrade" OR "affected system" OR "energy storage"',
  searchFullText: true,
  searchDescription: true,
  allDates: false,
  dateSearches: [
    { dateType: 'filed_date', startDate: start.toISOString(), endDate: end.toISOString() }
  ],
  classTypes: [],
  affiliations: [],
  availability: ['p'],
  categories: ['Submittal', 'Issuance'],
  libraries: ['Electric'],
  eFiling: false,
  sortBy: '',
  groupBy: 'NONE',
  resultsPerPage: 100,
  curPage: 1,
  idolResultID: '',
  accessionNumber: null
};

return [{ json: { body, windowStart: start.toISOString(), windowEnd: end.toISOString() } }];

// Keyword pre-filter: cheap regex gate before spending Claude tokens.
const KEYWORDS = [
  'interconnection', 'large load', 'co-location', 'colocation', 'data center',
  'queue reform', 'cost allocation', 'generator interconnection',
  'surplus interconnection service', 'gia', 'lgia', 'affected system',
  'network upgrade', 'point of interconnection', 'energy storage'
];
const rx = new RegExp(KEYWORDS.map(k => k.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')).join('|'), 'i');

const resp = $input.first().json;
const hits = Array.isArray(resp.searchHits) ? resp.searchHits : [];
const out = [];
for (const h of hits) {
  const hay = `${h.description || ''} ${(h.docketNumbers || []).join(' ')}`;
  if (!rx.test(hay)) continue;
  const acc = h.acesssionNumber || h.accessionNumber || ''; // source misspells this key
  out.push({
    json: {
      docketNumbers: h.docketNumbers || [],
      docketNo: (h.docketNumbers || [])[0] || '',
      accessionNumber: acc,
      description: h.description || '',
      category: h.category || '',
      filedDate: h.filedDate || '',
      issuedDate: h.issuedDate || '',
      affiliations: h.affiliations || [],
      eLibraryUrl: acc ? `https://elibrary.ferc.gov/eLibrary/filelist?accession_number=${acc}` : ''
    }
  });
}
return out;

// Score each filing with Claude, merge result back onto the filing, drop score <= 2.
// Done in one Code node so the filing's own fields (docket, URL, accession) never
// get clobbered by the API response. Requires ANTHROPIC_API_KEY in n8n env vars.
const API_KEY = $env.ANTHROPIC_API_KEY;
const SYS = 'You score FERC electric tariff filings for relevance to The Interconnect, a weekly publication read by renewable/storage developers, IPPs, and data-center power buyers. Score 1-5 for how much this filing matters to that audience. 5 = major queue reform, large-load/co-location policy, or cost-allocation shift with broad market impact. 1 = routine single-party rate tweak. Respond with ONLY a JSON object, no preamble, no markdown: {"score":1-5,"iso":"PJM|MISO|SPP|CAISO|NYISO|ISO-NE|multi|n/a","theme":"queue reform|large load|cost allocation|colocation|other","one_line":"<=20 words plain English"}';

const out = [];
for (const it of $input.all()) {
  const f = it.json;
  const userMsg = `Docket: ${f.docketNo}\nCategory: ${f.category}\nFiled: ${f.filedDate}\nDescription: ${f.description}`;
  let parsed = null;
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: { 'content-type': 'application/json', 'anthropic-version': '2023-06-01', 'x-api-key': API_KEY },
      body: { model: 'claude-sonnet-4-6', max_tokens: 300, system: SYS, messages: [{ role: 'user', content: userMsg }] },
      json: true,
      timeout: 30000
    });
    let txt = (r.content || []).filter(b => b.type === 'text').map(b => b.text).join('').replace(/```json|```/g, '').trim();
    parsed = JSON.parse(txt);
  } catch (e) { continue; } // API error or unparseable -> skip this filing
  if (!parsed || typeof parsed.score !== 'number' || parsed.score <= 2) continue;
  out.push({ json: {
    docketNo: f.docketNo,
    accessionNumber: f.accessionNumber,
    description: f.description,
    category: f.category,
    filedDate: f.filedDate,
    issuedDate: f.issuedDate,
    eLibraryUrl: f.eLibraryUrl,
    filer: (f.affiliations.find(a => a.afType === 'author') || {}).affiliation || '',
    score: parsed.score,
    iso: parsed.iso,
    theme: parsed.theme,
    one_line: parsed.one_line
  } });
}
return out;

// Failure branch: FERC ingest failed. Emit a Daily Brief alert payload.
const err = $input.first().json;
return [{ json: {
  alert: 'FERC_INGEST_FAILED',
  message: 'FERC eLibrary tariff ingest failed - check manually. The eLibrary backend is unofficial and may have changed shape or rate-limited.',
  httpCode: err.statusCode || err.code || 'unknown',
  ts: new Date().toISOString()
} }];
